fn main() {
    tauri_build::build();
}

# Workspace crates (Phase 0: just dependencies, no logic yet)
oceanix-lsp = { path = "../crates/oceanix-lsp" }
oceanix-pty = { path = "../crates/oceanix-pty" }
oceanix-git = { path = "../crates/oceanix-git" }
oceanix-search = { path = "../crates/oceanix-search" }
oceanix-ai = { path = "../crates/oceanix-ai" }
oceanix-plugin = { path = "../crates/oceanix-plugin" }
notify = "7"

[target.'cfg(target_os = "windows")'.dependencies]
windows = { version = "0.58", features = ["Win32_Foundation", "Win32_Graphics_Dwm"] }

{
  "$schema": "https://raw.githubusercontent.com/nicoverbruggen/tauri-v2-schema/refs/heads/main/tauri.conf.json",
  "productName": "Oceanix",
  "version": "0.1.0",
  "identifier": "com.oceanix.app",
  "build": {
    "frontendDist": "app/dist",
    "devUrl": "http://localhost:1420",
    "beforeDevCommand": "npm run dev --prefix app",
    "beforeBuildCommand": "npm run build --prefix app"
  },
  "app": {
    "windows": [
      {
        "title": "Oceanix",
        "width": 1200,
        "height": 800,
        "minWidth": 600,
        "minHeight": 400
      }
    ],
    "security": {
      "csp": null
    }
  },
  "bundle": {
    "active": false,
    "icon": [
      "icons/32x32.png",
      "icons/128x128.png",
      "icons/128x128@2x.png",
      "icons/icon.ico",
      "icons/icon.png"
    ]
  }
}

