#[tauri::command]
pub async fn terminal_create(shell: Option<String>, state: tauri::State<'_, crate::PtyState>) -> Result<TerminalCreateResult, String> {
    let pty = state.pty.clone();
    let result = tauri::async_runtime::spawn_blocking(move || {
